    fn fresh(&mut self) -> u64 {
        let n = self.next;
        self.next += 1;
        n
    }

    fn emit_addresss(&mut self, id: AddressId) -> u64 {
        if let Some(n) = self.addre_ids[id.0] {
            return n;
        }
        let it = self.model.addresss.get(id.0).clone();
        let n = self.fresh();
        self.addre_ids[id.0] = Some(n);
        let attrs: Vec<String> = vec![
            match &it.internal_location {
                Some(x) => step_str(x),
                None => "$".to_string(),
            },
            match &it.street_number {
                Some(x) => step_str(x),
                None => "$".to_string(),
            },
            match &it.street {
                Some(x) => step_str(x),
                None => "$".to_string(),
            },
            match &it.postal_box {
                Some(x) => step_str(x),
                None => "$".to_string(),
            },
            match &it.town {
                Some(x) => step_str(x),
                None => "$".to_string(),
            },
            match &it.region {
                Some(x) => step_str(x),
                None => "$".to_string(),
            },
            match &it.postal_code {
                Some(x) => step_str(x),
                None => "$".to_string(),
            },
            match &it.country {
                Some(x) => step_str(x),
                None => "$".to_string(),
            },
            match &it.facsimile_number {
                Some(x) => step_str(x),
                None => "$".to_string(),
            },
            match &it.telephone_number {
                Some(x) => step_str(x),
                None => "$".to_string(),
            },
            match &it.electronic_mail_address {
                Some(x) => step_str(x),
                None => "$".to_string(),
            },
            match &it.telex_number {
                Some(x) => step_str(x),
                None => "$".to_string(),
            },
        ];
        self.out
            .push_str(&format!("#{n} = ADDRESS({});\n", attrs.join(",")));
        n
    }

